sql:
SELECT status, COUNT(*) AS cart_count, SUM(total_items) AS total_items_sum
FROM carts
GROUP BY status;

SELECT status, total_price
FROM carts
ORDER BY total_price DESC;

external_knowledge:
- Abandoned carts refer to carts that have been left without a purchase for a certain period; 
- Purchased carts refer to carts that have been successfully checked out and paid for; 
- Active carts refer to carts that are currently being edited or have items added or removed but have not been checked out yet.

sql:
SELECT user_id, status, total_price
FROM carts
ORDER BY total_price DESC;

SELECT cart_id, total_items AS total_items_in_cart, total_price AS total_price_of_cart, status
FROM carts
ORDER BY total_price DESC;
